import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import Modal from "../components/Modal";

function Admin() {
  const [teachers, setTeachers] = useState([]);
  const [students, setStudents] = useState([]);
  const [courses, setCourses] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [itemToDelete, setItemToDelete] = useState(null);
  const [deleteType, setDeleteType] = useState("");
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();

  useEffect(() => {
    if (!user || user.role !== "admin") {
      navigate("/dashboard");
    }
    fetch("http://localhost:3001/users?role=teacher")
      .then((res) => res.json())
      .then((data) => setTeachers(data));
    fetch("http://localhost:3001/users?role=student")
      .then((res) => res.json())
      .then((data) => setStudents(data));
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data));
  }, [user, navigate]);

  async function handleDelete() {
    const url = `http://localhost:3001/${deleteType}/${itemToDelete}`;
    const response = await fetch(url, {
      method: "DELETE",
    });
    if (response.ok) {
      if (deleteType === "users") {
        setTeachers(teachers.filter((t) => t.id !== itemToDelete));
        setStudents(students.filter((s) => s.id !== itemToDelete));
        toast.success("User deleted successfully!");
      } else {
        setCourses(courses.filter((c) => c.id !== itemToDelete));
        toast.success("Course deleted successfully!");
      }
    } else {
      toast.error(`Failed to delete ${deleteType === "users" ? "user" : "course"}`);
    }
    setIsModalOpen(false);
  }

  function openModal(id, type) {
    setItemToDelete(id);
    setDeleteType(type);
    setIsModalOpen(true);
  }

  return (
    <div className="page-container">
      <h1>Admin Panel</h1>

      <h2>Teachers</h2>
      <ul>
        {teachers.map((teacher) => (
          <li key={teacher.id}>
            {teacher.name} ({teacher.email})
            <button onClick={() => openModal(teacher.id, "users")}>Delete</button>
          </li>
        ))}
      </ul>

      <h2>Students</h2>
      <ul>
        {students.map((student) => (
          <li key={student.id}>
            {student.name} ({student.email})
            <button onClick={() => openModal(student.id, "users")}>Delete</button>
          </li>
        ))}
      </ul>

      <h2>Courses</h2>
      <ul>
        {courses.map((course) => (
          <li key={course.id}>
            {course.name} - {course.description}
            <Link to={`/edit-course/${course.id}`}>
              <button>Edit</button>
            </Link>
            <button onClick={() => openModal(course.id, "courses")}>Delete</button>
          </li>
        ))}
      </ul>

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleDelete}
        message={`Are you sure you want to delete this ${deleteType === "users" ? "user" : "course"}?`}
      />
    </div>
  );
}

export default Admin;
